CREATE TABLE target_companies (
  id BIGSERIAL PRIMARY KEY,
  name TEXT NOT NULL UNIQUE CHECK (length(trim(name)) > 0),
  company_url TEXT,
  career_url TEXT,
  linkedin_url TEXT,
  region TEXT,
  primary_location TEXT,
  germany_offices TEXT,
  additional_offices TEXT,
  industry TEXT,
  company_type TEXT,
  description TEXT,
  work_mode TEXT,
  employee_count TEXT,
  visa_signal TEXT,
  relocation_signal TEXT,
  fit_notes TEXT,
  source TEXT,
  source_notes TEXT,
  last_checked_date DATE,
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TRIGGER target_companies_set_updated_at
BEFORE UPDATE ON target_companies
FOR EACH ROW
EXECUTE FUNCTION set_updated_at();

CREATE INDEX target_companies_is_active_idx
ON target_companies(is_active, updated_at DESC);

CREATE INDEX target_companies_region_idx
ON target_companies(region);

ON CONFLICT (name) DO UPDATE SET
  company_url = COALESCE(EXCLUDED.company_url, target_companies.company_url),
  career_url = COALESCE(EXCLUDED.career_url, target_companies.career_url),
  linkedin_url = COALESCE(EXCLUDED.linkedin_url, target_companies.linkedin_url),
  region = COALESCE(EXCLUDED.region, target_companies.region),
  primary_location = COALESCE(EXCLUDED.primary_location, target_companies.primary_location),
  germany_offices = COALESCE(EXCLUDED.germany_offices, target_companies.germany_offices),
  additional_offices = COALESCE(EXCLUDED.additional_offices, target_companies.additional_offices),
  industry = COALESCE(EXCLUDED.industry, target_companies.industry),
  company_type = COALESCE(EXCLUDED.company_type, target_companies.company_type),
  description = COALESCE(EXCLUDED.description, target_companies.description),
  work_mode = COALESCE(EXCLUDED.work_mode, target_companies.work_mode),
  employee_count = COALESCE(EXCLUDED.employee_count, target_companies.employee_count),
  visa_signal = COALESCE(EXCLUDED.visa_signal, target_companies.visa_signal),
  relocation_signal = COALESCE(EXCLUDED.relocation_signal, target_companies.relocation_signal),
  fit_notes = COALESCE(EXCLUDED.fit_notes, target_companies.fit_notes),
  source = COALESCE(EXCLUDED.source, target_companies.source),
  source_notes = COALESCE(EXCLUDED.source_notes, target_companies.source_notes),
  last_checked_date = COALESCE(EXCLUDED.last_checked_date, target_companies.last_checked_date),
  is_active = EXCLUDED.is_active,
  updated_at = now();
